messages.content:
你是 QA 项目的 attribute agent。
只基于当前 QA 样本的 question、provided contexts、reference answer、actual answer、qa_local_evidence_probe 和 semantic judge 结果归因；该项目没有外部 QA 服务调用，不能把失败归因到不存在的远端服务。
当 judge 为 not_evaluable 或本地 probe 显示缺少 reference/actual 语义证据时，不要编造根因，evidence_strength 设为 none 或 weak，并在 root_cause_hypothesis 说明缺失证据。
最终只输出 AttributeResult JSON 所需字段：expectation_attributions、suspected_locations、root_cause_hypothesis、evidence、evidence_strength。

## 输出约束：attribute 归因分析输出
你的输出必须是合法 JSON，且严格符合以下 JSON Schema：
```json
{
  "type": "object",
  "properties": {
    "expectation_attributions": {
      "type": "array",
      "items": {
        "$ref": "#/$defs/ExpectationAttribution"
      },
      "minItems": 1
    },
    "suspected_locations": {
      "type": "array",
      "items": {}
    },
    "root_cause_hypothesis": {
      "type": "string",
      "minLength": 1
    },
    "evidence": {
      "type": "array",
      "items": {}
    },
    "evidence_strength": {
      "type": "string",
      "minLength": 1
    }
  },
  "additionalProperties": false,
  "$defs": {
    "ExpectationAttribution": {
      "type": "object",
      "properties": {
        "expectation_id": {
          "type": "string",
          "minLength": 1
        },
        "fulfillment_status": {
          "type": "string",
          "minLength": 1
        },
        "suspected_locations": {
          "type": "array",
          "items": {}
        },
        "root_cause_hypothesis": {
          "type": "string",
          "minLength": 1
        },
        "evidence": {
          "type": "array",
          "items": {}
        }
      },
      "additionalProperties": false,
      "required": [
        "expectation_id",
        "fulfillment_status"
      ]
    }
  },
  "required": [
    "expectation_attributions",
    "root_cause_hypothesis"
  ]
}
```

### 强约束
- 最终回答必须只包含一个 JSON object；不要输出 Markdown，不要使用 ```json 代码块，不要在 JSON 外输出解释、前缀或后缀。
- 最终回答首字符必须是 `{`，末字符必须是 `}`。
- JSON 字符串内部如需引用用户原词，禁止直接写未转义英文双引号；请使用中文引号“”或转义为 `\"`。
- 必须包含 `required` 列表中的所有字段。
- 每个字段值必须匹配 schema 中的类型。
- 以下字段必须非空（空字符串/空数组/空对象/None 均视为不合规，会被阻断）：['expectation_attributions', 'root_cause_hypothesis']
- `additionalProperties: false`：禁止输出 schema 未定义的字段。
- 禁止把 schema 里的类型描述符（如 "string"）原样当作内容填进去——每个字段必须填入真实内容。

{
  "expectation_attributions": [
    {
      "expectation_id": "说明分组限制",
      "fulfillment_status": "not_fulfilled",
      "suspected_locations": [
        "actual_answer"
      ],
      "root_cause_hypothesis": "实际回答未包含轻症分组限制的说明，可能因为实际回答侧重于直接回答赔付次数和金额比例的核心问题，忽略了该限制条件，导致未覆盖 reference 中的此项信息。",
      "evidence": [
        "judge_result: expected_evidence = '轻症责任可能设有分组限制，即同一组别的轻症只能赔付一次', actual_evidence = '回答中未提及分组限制'"
      ]
    },
    {
      "expectation_id": "说明轻症赔付对重疾保额的影响",
      "fulfillment_status": "not_fulfilled",
      "suspected_locations": [
        "actual_answer"
      ],
      "root_cause_hypothesis": "实际回答未提及轻症赔付后重疾保额可能不变或减少的情况，可能因为回答简化，只传达了轻症赔付规则，而忽略了其对主险保额的潜在影响。",
      "evidence": [
        "judge_result: expected_evidence = '部分产品轻症赔付后重疾保额不变，部分产品会相应减少', actual_evidence = '回答中未提及'"
      ]
    },
    {
      "expectation_id": "说明合同继续有效及累计上限",
      "fulfillment_status": "not_fulfilled",
      "suspected_locations": [
        "actual_answer"
      ],
      "root_cause_hypothesis": "实际回答未说明轻症赔付后合同继续有效及累计赔付上限，可能是因为回答聚焦于赔付机制本身，未延伸到合同效力和总量限制层面。",
      "evidence": [
        "judge_result: expected_evidence = '轻症赔付后合同继续有效，但累计赔付上限可能有限制', actual_evidence = '回答中未提及'"
      ]
    }
  ],
  "suspected_locations": [
    "actual_answer (provided output)"
  ],
  "root_cause_hypothesis": "实际回答覆盖了轻症多次赔付、赔付比例、次数上限和间隔期等核心信息，但遗漏了reference中关于分组限制、轻症赔付对重疾保额的影响、合同继续有效及累计赔付上限等关键细节。这属于回答内容不完整，未能全面覆盖reference answer中的所有重要信息点。",
  "evidence": [
    "qa_local_evidence_probe: question_present=true, reference_answer_present=true, actual_answer_present=true, judge_status=not_fulfilled",
    "judge_result.overall_fulfillment: score=0.625, description='实际回答回答了核心问题，但遗漏了分组限制、轻症对重疾保额的影响以及累计赔付上限等关键信息'",
    "reference_answer: 包含分组限制、保额影响、合同继续有效及累计上限等描述",
    "actual_answer: 未包含上述信息"
  ],
  "evidence_strength": "strong"
}

